1	const PROCESSING_FEE = 5;
2	
3	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	};
9	
10	const COMPONENT_PREMIUM = 25;
11	const COMPONENT_BLOCK_PREMIUM = 60;
12	const COMPONENT_BLOCK_SIZE = 3;
13	
14	const isComponent = (type: string): boolean => !MAIN_ITEM_PREMIUMS.hasOwnProperty(type);
15	
16	const calculateBasePremium = (items: { type: string }[]): number => {
17	  let total = 0;
18	
19	  const componentCounts: Record<string, number> = {};
20	  for (const item of items) {
21	    if (isComponent(item.type)) {
22	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
23	    } else {
24	      total += MAIN_ITEM_PREMIUMS[item.type] ?? 0;
25	    }
26	  }
27	
28	  for (const count of Object.values(componentCounts)) {
29	    if (count === COMPONENT_BLOCK_SIZE) {
30	      total += COMPONENT_BLOCK_PREMIUM;
31	    } else {
32	      total += count * COMPONENT_PREMIUM;
33	    }
34	  }
35	
36	  return total;
37	};
38	
39	export function processScenario(scenario: { steps: { op: string; items?: { type: string }[] }[] }): { results: unknown[] } {
40	  const results = scenario.steps.map((step) => {
41	    const premium = calculateBasePremium(step.items ?? []) + PROCESSING_FEE;
42	    return { premium };
43	  });
44	  return { results };
45	}
